    requireAllowed(SystemAddresses.GOVERNANCE);
    _requireInitialized();
    if (_epochIntervalMicros == 0) { revert Errors.InvalidEpochInterval(); }
    _pendingEpochIntervalMicros = _epochIntervalMicros;
    hasPendingConfig = true;
