}

function governanceReconfigure() external override {
    requireAllowed(SystemAddresses.GOVERNANCE);
    _requireInitialized();
    if (_transitionState == TransitionState.DkgInProgress) { revert ... }
    ...
    if (config.variant == RandomnessConfig.ConfigVariant.Off) { _doImmediateReconfigure(); }
    else { _startDkgSession(config); }
}
